from __future__ import annotations

import shutil
from pathlib import Path

from docx import Document
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Cm, Pt
from docx.text.paragraph import Paragraph


ROOT = Path(__file__).resolve().parent
SOURCE = ROOT / "MindHelper_diploma_v5_final.docx"
TARGET = ROOT / "MindHelper_diploma_v6_expanded.docx"

STYLE_BODY = "Основной текст курсовой"
STYLE_CAPTION = "Название рисунка"
STYLE_CODE = "Код"


def insert_after(paragraph: Paragraph, text: str, style: str = STYLE_BODY) -> Paragraph:
    new_p = OxmlElement("w:p")
    paragraph._p.addnext(new_p)
    p = Paragraph(new_p, paragraph._parent)
    p.style = style
    p.add_run(text)
    return p


def insert_block_after_heading(document: Document, heading: str, paragraphs: list[str]) -> None:
    anchor = next((p for p in document.paragraphs if p.text.strip() == heading), None)
    if anchor is None:
        raise RuntimeError(f"Heading not found: {heading}")
    current = anchor
    for text in paragraphs:
        current = insert_after(current, text)


def apply_text_formatting(document: Document) -> None:
    for paragraph in document.paragraphs:
        text = paragraph.text.strip()
        if not text:
            continue

        if text.startswith("Рисунок ") or text.startswith("Таблица "):
            paragraph.style = STYLE_CAPTION
            paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
            paragraph.paragraph_format.first_line_indent = Cm(0)

        for run in paragraph.runs:
            if paragraph.style.name == STYLE_CODE:
                run.font.name = "Courier New"
                run._element.rPr.rFonts.set(qn("w:eastAsia"), "Courier New")
                run.font.size = Pt(9)
            else:
                run.font.name = "Times New Roman"
                run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
                run.font.size = Pt(14)


